     }

     // ── ApplyCoupon ──────────────────────────────────────────

     [TestMethod]
     public void ApplyCoupon_ValidCode_DiscountsTotal()
     {
         _cart.AddItem("SKU-001", 1, 100.00m);
         _cart.ApplyCoupon("SAVE10");

         var total = _cart.CalculateTotal();
         Assert.IsGreaterThan(total, 0m);
         Assert.IsLessThan(total, 100.00m);
     }

